head.script:
scwin.isDelete;
scwin.isUpdate;
scwin.spplyAmt	    = 0;
scwin.vatAmt        = 0;
scwin.spplyAmtFcrc  = 0;
scwin.bilgAmt       = 0;
scwin.bilgAmtFcrc   = 0;
scwin.fcrcBilgAmt   = 0;
scwin.clntMgntYn    = 0; //관리거래처 체크 	

scwin.onpageload = function () {
    const codeOptions = [
        { grpCd : "SD070", compID : "acb_taxnClsCd", opt:{"range":"1"} } 
      , { grpCd : "FS500", compID : "gr_commonList:dcsnClsCd", opt:{"range":"1"} } 
    ];
    $c.data.setCommonCode(codeOptions);    	

    var purchaseEvidence = opener[JSON.parse($p.getPopupParam()).menuInfo.pFrmId].getWindow().ds_purchaseEvidence;
    var commonList = opener[JSON.parse($p.getPopupParam()).menuInfo.pFrmId].getWindow().ds_commonCopyList;

    $c.gus.cfCopyDataSet(purchaseEvidence, ds_purchaseEvidence);
    $c.gus.cfCopyDataSet(commonList, ds_commonList);

    if(ds_purchaseEvidence.getCellData(0, "slipNo") != null && ds_purchaseEvidence.getCellData(0, "slipNo") != ""){
        gr_commonList.setColumnVisible("chk", false); 
        var cnt = ds_commonList.getRowCount();

        for (var i = cnt - 1; i >= 0; i--) { 
            if (ds_commonList.getCellData(i, "chk") != "T") {
                // ds_commonList.DeleteRow(i);
                ds_commonList.removeRow(i);
            }
        }
        $c.gus.cfDisableBtn([btn_save]);
    } else {
        var cnt = ds_commonList.getRowCount();
        for (var i = cnt - 1; i >= 0; i--) { 
            if (ds_commonList.getCellData(i, "chk") != "T") {
                //ds_commonList.DeleteRow(i);
                ds_commonList.removeRow(i);
            }
        }
        $c.gus.cfDisableBtn([btn_delete]);
    }

    $c.gus.cfEnableObj(ica_slipCloseYm, false);
    $c.gus.cfEnableObj(ica_taxCloseYm, false);


};

scwin.onUdcCompleted = function () {

};

scwin.ondataload = function () {
   scwin.f_pushPchaseEvidence();
};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
// 화면종료시
scwin.f_OnUnload = function () {
    var returnObject = new Object();
    if(scwin.isDelete){
        returnObject.flag 		= "DELETE";    
        returnObject.curRow 	= ds_purchaseEvidence.getCellData(0, "curRow");
    } else if(scwin.isUpdate) {
        returnObject.flag 		= "UPDATE";   
        returnObject.curRow 	= ds_purchaseEvidence.getCellData(0, "curRow");
        returnObject.sellVatNo 	= ds_purchaseEvidence.getCellData(0, "sellVatNo");
        returnObject.slipNo 	= ds_purchaseEvidence.getCellData(0, "slipNo");
        returnObject.dcsnClsNm 	= ds_purchaseEvidence.getCellData(0, "dcsnClsNm");
        returnObject.spplyDt 	= ds_purchaseEvidence.getCellData(0, "spplyDt");
        returnObject.slipDt 	= ds_purchaseEvidence.getCellData(0, "slipDt");
        returnObject.summary	= ds_purchaseEvidence.getCellData(0, "summary");        
    } else {
        returnObject.curRow 	= ds_purchaseEvidence.getCellData(0, "curRow");
        returnObject.spplyDt 	= ica_spplyDt.getValue();
        returnObject.slipDt 	= ica_slipDt.getValue();
        returnObject.summary 	= ed_summary.getValue();
    }

    $c.win.closePopup(returnObject);   
};

// 매출증빙 화면 세팅
scwin.f_pushPchaseEvidence = function () {
    ed_busiNo.setValue(ds_purchaseEvidence.getCellData(0, "busiNo"));
    acb_evidKndClsCd.setValue(ds_purchaseEvidence.getCellData(0, "evidKndClsCd"));
    acb_taxnClsCd.setValue(ds_purchaseEvidence.getCellData(0, "taxnClsCd"));
    ed_pchsVatNo.setValue(ds_purchaseEvidence.getCellData(0, "sellVatNo"));
    ica_spplyDt.setValue(ds_purchaseEvidence.getCellData(0, "spplyDt"));
    ed_busiNm.setValue(ds_purchaseEvidence.getCellData(0, "pchsClntNm"));
    ed_repstNm.setValue(ds_purchaseEvidence.getCellData(0, "repstNm"));
    ed_pchsDeptCd.setValue(ds_purchaseEvidence.getCellData(0, "pchsDeptCd"));
    ed_pchsDeptNm.setValue(ds_purchaseEvidence.getCellData(0, "pchsDeptNm"));
    ed_slipNo.setValue(ds_purchaseEvidence.getCellData(0, "slipNo"));
    ica_slipDt.setValue(ds_purchaseEvidence.getCellData(0, "slipDt"));
    ed_summary.setValue(ds_purchaseEvidence.getCellData(0, "summary"));
    ed_spplyAmt.setValue(ds_purchaseEvidence.getCellData(0, "spplyAmt"));
    ed_vatAmt.setValue(ds_purchaseEvidence.getCellData(0, "vat"));
    ed_sumAmt.setValue(ds_purchaseEvidence.getCellData(0, "sumAmt"));

    ica_slipCloseYm.setValue(ds_purchaseEvidence.getCellData(0, "slipCloseYm"));
    ica_taxCloseYm.setValue(ds_purchaseEvidence.getCellData(0, "taxCloseYm"));

    totalRows.setValue(ds_commonList.getRowCount());
};

// 매출증빙 화면 세팅(저장버튼이후 결과값)
scwin.f_pushSellingEvidence = function () {
    ed_pchsVatNo.setValue(ds_purchaseEvidenceResult.getCellData(0, "pchsVatNo"));
    ed_slipNo.setValue(ds_purchaseEvidenceResult.getCellData(0, "slipNo"));
    ds_commonList.setCellData(0, "slipNo", ds_purchaseEvidenceResult.getCellData(0, "slipNo"));
    ds_commonList.setCellData(0, "sellVatNo", ds_purchaseEvidenceResult.getCellData(0, "pchsVatNo"));
};

// 저장
scwin.f_Save = async function () {
    // 세금계산서가 발행되었으면....
    if (ds_purchaseEvidence.getCellData(0, "slipNo") != null && ds_purchaseEvidence.getCellData(0, "slipNo") != "") {
        await $c.gus.cfAlertMsg("매출증빙 내역이 있는 자료는 저장 할 수 없습니다.");
        return;
    }

    // validation check     
    if (!await $c.gus.cfValidate([ica_spplyDt, ica_slipDt, ed_summary])) {
        return;
    }

    $c.gus.cfCopyDataSetHeader(ds_commonList, ds_commonRetriveList);
    var	transRow;
    var chkCnt = 0;
    for (var i = 0; i < ds_commonList.getRowCount(); i++) {
        if( ds_commonList.getCellData(i, "chk") == "T" ) {
            ds_commonRetriveList.setRowJSON(chkCnt, ds_commonList.getRowJSON(i), true);
            chkCnt++;
        }
    }

    if (chkCnt < 1) {  
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007,["저장할 거래명세서"]);
        return;
    }

    let saveChk = await $c.win.confirm(MSG_CM_CRM_001); 
    if(!saveChk){ 
        return;
    } 

    ds_purchaseEvidence.setCellData(0, "spplyAmt", ed_spplyAmt.getValue());
    ds_purchaseEvidence.setCellData(0, "vatAmt", ed_vatAmt.getValue());
    ds_purchaseEvidence.setCellData(0, "sumAmt", ed_sumAmt.getValue());
    ds_purchaseEvidence.setCellData(0, "spplyDt", ica_spplyDt.getValue());
    ds_purchaseEvidence.setCellData(0, "slipDt", ica_slipDt.getValue());
    ds_purchaseEvidence.setCellData(0, "summary", ed_summary.getValue());
    ds_purchaseEvidence.setCellData(0, "certiCnt", chkCnt);

    let e = await $c.sbm.execute(sbm_createTaxInvoice);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_createTaxInvoice_submitdone(e);
    }
};

// 삭제
scwin.f_Delete = async function () {
    // 세금계산서가  발행 안되었으면....
    if (ds_purchaseEvidence.getCellData(0, "slipNo") == null || ds_purchaseEvidence.getCellData(0, "slipNo") == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["삭제할 세금계산서"]);
        return;
    }

    let saveChk = await $c.win.confirm(MSG_CM_CRM_004); 
    if(!saveChk){ 
        return;
    } 

    let taxChk = await scwin.f_CheckTaxCancelSpplyDt(); 
    if( !taxChk ) { 
        return;
    }

    ds_purchaseEvidence.setCellData(0, "cancelSpplyDt", ica_cancelSpplyDt.getValue());

    let e = await $c.sbm.execute(sbm_deleteTaxInvoice);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_deleteTaxInvoice_submitdone(e);
    }
};

// 세금계산서 취소 때  세무마감여부 CHECK
scwin.f_CheckTaxCancelSpplyDt = async function () {
    var taxCloseYm  = ica_taxCloseYm.getValue();
    var spplyYm		= ica_spplyDt.getValue().substring(0,6);
    var isTrue;

    if ( taxCloseYm >= spplyYm ) {
        isTrue = await $c.win.confirm("세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)\n\n세금계산서 및 전표를 취소하시겠습니까?");
        if (!isTrue) {
            return false; 
        } 

        if ($c.gus.cfIsNull(ica_cancelSpplyDt.getValue())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["[수정세금계산서 공급일자 ]"]); //@은(는) 필수 입력 항목입니다
            ica_cancelSpplyDt.focus();
            return false;
        }

        let ret1 = await $c.gus.cfValidate([ica_cancelSpplyDt]);
        if (!ret1) {
            ica_cancelSpplyDt.focus();
            return false;
        } 

    } 

    return true;
};

// 엑셀 다운로드
scwin.f_downExcelSheet = async function () {
    if (await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
        $c.data.downloadGridViewExcel(gr_commonList, {"fileName": "거래명세서별 청구서 내역.xlsx", "sheetName": "거래명세서별 청구서 내역"});
    }
};

//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
// 계약거래처

//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_createTaxInvoice_submitdone = async function (e) {
    await $c.gus.cfAlertMsg([MSG_CM_INF_001]);
};

scwin.sbm_deleteTaxInvoice_submitdone = async function (e) {
    if (await $c.gus.cfAlertMsg([MSG_CM_INF_004])) {
        scwin.isDelete = true;
        scwin.f_OnUnload();
    };
};

//-------------------------------------------------------------------------
// Event onClick
//-------------------------------------------------------------------------
// 닫기 버튼 클릭 이벤트 
scwin.btn_close_onclick = function (e) {
    scwin.f_OnUnload(); 
};

// 저장 버튼 클릭 이벤트
scwin.btn_save_onclick = function (e) {
    scwin.f_Save()
};

// 삭제 버튼 클릭 이벤트 
scwin.btn_delete_onclick = function (e) {
    scwin.f_Delete();
};

//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// Event onblur
//-------------------------------------------------------------------------
// 계약처 Onbluer(onKillFocus) 이벤트 발생시

//-------------------------------------------------------------------------
// Event onviewchange
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// DataSet 이벤트
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_commonList_onheaderclick = function (headerId) {
    var i = 0;

    if (headerId == "column1")	{
        var bCheck = gr_commonList.getHeaderValue(headerId); 
        spplyAmt = 0;
        vatAmt = 0;
        spplyAmtFcrc = 0;
        bilgAmt = 0;
        bilgAmtFcrc = 0;
        fcrcBilgAmt = 0;
        if (bCheck == "1") {
            for (var i = 0; i < ds_commonList.getRowCount(); i++) { 
				ds_commonList.setCellData(i, "chk", "T");
		  		spplyAmt = spplyAmt + Number(ds_commonList.getCellData(i, "spplyAmt"));
		  		vatAmt = vatAmt + Number(ds_commonList.getCellData(i, "vat"));
		  		spplyAmtFcrc = spplyAmtFcrc + Number(ds_commonList.getCellData(i, "spplyAmtFcrc"));
		  		bilgAmt = bilgAmt + Number(ds_commonList.getCellData(i, "bilgAmt"));
		  		bilgAmtFcrc = bilgAmtFcrc + Number(ds_commonList.getCellData(i, "bilgAmtFcrc"));
		  		fcrcBilgAmt = fcrcBilgAmt + Number(ds_commonList.getCellData(i, "fcrcBilgAmt"));
            }

            ed_spplyAmt.setValue(spplyAmt);
            ed_vatAmt.setValue(vatAmt);
            ed_sumAmt.setValue(spplyAmt + vatAmt);

            ds_purchaseEvidence.setCellData(0, "bilgAmtFcrc", bilgAmtFcrc);
            ds_purchaseEvidence.setCellData(0, "fcrcBilgAmt", fcrcBilgAmt);
            ds_purchaseEvidence.setCellData(0, "bilgAmt", bilgAmt);

        } else {
            for (var i = 0; i<ds_commonList.getRowCount(); i++) {
                ds_commonList.setCellData(i, "chk", "F");
            }

            ed_spplyAmt.setValue(0);
            ed_vatAmt.setValue(0);
            ed_sumAmt.setValue(0);

			ds_purchaseEvidence.setCellData(0, "bilgAmt", 0);
			ds_purchaseEvidence.setCellData(0, "bilgAmtFcrc", 0);
			ds_purchaseEvidence.setCellData(0, "fcrcBilgAmt", 0);
        }
    }
};


//-------------------------------------------------------------------------
// InputBox 대문자 설정
//-------------------------------------------------------------------------
